def _response_parts_to_a2a(self, parts: Sequence[ModelResponsePart]) -> list[Part]:
    a2a_parts: list[Part] = []
    for part in parts:
        if isinstance(part, TextPart):
            a2a_parts.append(A2ATextPart(kind='text', text=part.content))
        elif isinstance(part, ThinkingPart):
            a2a_parts.append(A2ATextPart(
                kind='text', text=part.content,
                metadata={'type': 'thinking', 'thinking_id': part.id}
            ))
        elif isinstance(part, ToolCallPart):
            # 跳过工具调用 - 内部执行细节
            pass
    return a2a_parts
